const renderBlockImage = (widgetId, block) => {
    if(!block?.image_url){
        return null;
    }
    const isActive = activeBlockImageState?.widgetId === widgetId && activeBlockImageState?.blockId === block.id;
    const isResizing = blockImageResizeState?.widgetId === widgetId && blockImageResizeState?.blockId === block.id;
    return (
        <div
            className={`profile-widget-block-image-wrapper${isActive ? ' is-active' : ''}${isResizing ? ' is-resizing' : ''}`}
            style={{width: Number.isFinite(block.image_width) ? `${block.image_width}px` : undefined}}
            onMouseDown={(e) => {
                if(!(e.target instanceof Element)){
                    return;
                }
                if(e.target.closest('button')){
                    e.stopPropagation();
                }
            }}
            onClick={(e) => {
                e.stopPropagation();
                setActiveWidgetId(widgetId);
                setActiveBlockImageState({widgetId, blockId: block.id});
            }}
        >
            <img
                className="profile-widget-block-image"
                src={block.image_url}
                alt={block.title || 'block'}
                draggable="false"
                style={{
                    height: Number.isFinite(block.image_height) ? `${block.image_height}px` : undefined,
                    width: Number.isFinite(block.image_width) ? '100%' : undefined
                }}
            />
            {(Number.isFinite(block.image_width) || Number.isFinite(block.image_height)) && (
                <div className="profile-widget-image-dimensions">
                    {block.image_width ?? '—'} &times; {block.image_height ?? '—'}
                </div>
            )}
            {(Number.isFinite(block.image_width) || Number.isFinite(block.image_height)) && (
                <button
                    type="button"
                    className="profile-widget-block-image-reset-btn"
                    onMouseDown={(e) => {
                        e.stopPropagation();
                    }}
                    onClick={(e) => {
                        e.stopPropagation();
                        handleResetBlockImageSize(widgetId, block.id);
                    }}
                >
                    Reset
                </button>
            )}
            <button type="button" className="profile-widget-image-handle corner-tl" onMouseDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'corner-tl')} aria-label="Resize block image from top-left" />
            <button type="button" className="profile-widget-image-handle corner-tr" onMouseDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'corner-tr')} aria-label="Resize block image from top-right" />
            <button type="button" className="profile-widget-image-handle corner-bl" onMouseDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'corner-bl')} aria-label="Resize block image from bottom-left" />
            <button type="button" className="profile-widget-image-handle corner-br" onMouseDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'corner-br')} aria-label="Resize block image from bottom-right" />
            <button type="button" className="profile-widget-image-handle side-right" onMouseDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'right')} aria-label="Resize block image width" />
            <button type="button" className="profile-widget-image-handle side-bottom" onMouseDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'bottom')} aria-label="Resize block image height" />
        </div>
    );
};
